import json
import re
from collections import defaultdict

# Load users who registered in 2016
users_2016_file = locals()['var_functions.query_db:30']
if isinstance(users_2016_file, str):
    with open(users_2016_file, 'r') as f:
        users_2016 = json.load(f)
else:
    users_2016 = users_2016_file

user_ids_2016 = [user['user_id'] for user in users_2016]
print(f"Loaded {len(user_ids_2016)} users from 2016")

# Create regex patterns for date matching since we have mixed formats
patterns = [
    r'(\d{4})-\d{2}-\d{2}',  # YYYY-MM-DD format
    r'(\d{4})',  # Just year
    r'.*(\d{4}).*'  # Year somewhere in string
]

def extract_year(date_str):
    if not date_str:
        return None
    for pattern in patterns:
        match = re.search(pattern, date_str)
        if match:
            try:
                year = int(match.group(1))
                return year
            except:
                continue
    return None

# Filter for users who registered in 2016 (verify)
filtered_users = []
for user in users_2016:
    year = extract_year(user.get('yelping_since', ''))
    if year == 2016:
        filtered_users.append(user['user_id'])

print(f"Confirmed {len(filtered_users)} users registered in 2016")
print('__RESULT__:')
print(json.dumps({
    "user_count": len(filtered_users),
    "sample_users": filtered_users[:5]
}))

