import json

# Load reviews
reviews_file = locals()['var_functions.query_db:48']
if isinstance(reviews_file, str):
    with open(reviews_file, 'r') as f:
        reviews = json.load(f)
else:
    reviews = reviews_file

print(f"Processing {len(reviews)} reviews")

# Group reviews by business_ref to count them
business_review_counts = {}
for review in reviews:
    business_ref = review['business_ref']
    if business_ref:
        business_review_counts[business_ref] = business_review_counts.get(business_ref, 0) + 1

print(f"Review counts by business:")
for ref, count in list(business_review_counts.items())[:5]:
    print(f"  {ref}: {count} reviews")

print('__RESULT__:')
print(json.dumps({
    "total_reviews": len(reviews),
    "unique_businesses": len(business_review_counts),
    "sample_counts": {k: business_review_counts[k] for k in list(business_review_counts.keys())[:3]}
}))

